      setStats({ total: 0, done: 0 }); // fallback properties
    });
  }, [groupId]);

  const progress = stats.total > 0 ? Math.round((stats.done / stats.total) * 100) : 0;

  return (
    <div className="flex min-h-screen bg-white">
